    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Build a Steiner tree approximation to maximize shared edges
    # Start with shortest paths and incrementally add destinations
    tree_nodes = {src}  # Nodes already in the multicast tree
    tree_edges = {}     # (s, t) -> edge data for edges in tree
    dst_paths = {}      # dst -> path from src (or nearest tree node) to dst

    # Sort destinations by distance from source to prioritize closer ones
    dst_distances = []
    for dst in dsts:
        try:
            dist = nx.dijkstra_path_length(h, src, dst, weight="cost")
            dst_distances.append((dist, dst))
        except nx.NetworkXNoPath:
            dst_distances.append((float('inf'), dst))

    dst_distances.sort()

    # Build tree incrementally - find best connection from tree to each destination
    for _, dst in dst_distances:
        # Find cheapest connection from any tree node to this destination
        best_full_path = None
        best_cost = float('inf')
        best_new_cost = float('inf')  # Cost of new edges only (for maximizing reuse)

        for tree_node in tree_nodes:
            try:
                # Get path from this tree node to destination
                path_segment = nx.dijkstra_path(h, tree_node, dst, weight="cost")
                segment_cost = sum(G[path_segment[i]][path_segment[i+1]]['cost'] 
                                 for i in range(len(path_segment)-1))

                # Build full path from source
                if tree_node == src:
                    full_path = path_segment
                    full_cost = segment_cost
                    new_cost = segment_cost
                else:
                    # Get path from src to tree_node using tree edges when possible
                    if tree_node in dst_paths:
                        # Reuse existing path to tree node
                        prefix = dst_paths[tree_node]
                        prefix_cost = sum(G[prefix[i]][prefix[i+1]]['cost'] 
                                        for i in range(len(prefix)-1))
                    else:
                        # Need to find path from src to tree_node
                        try:
                            prefix = nx.dijkstra_path(h, src, tree_node, weight="cost")
                            prefix_cost = sum(G[prefix[i]][prefix[i+1]]['cost'] 
                                            for i in range(len(prefix)-1))
                        except nx.NetworkXNoPath:
                            continue

                    # Merge paths, avoiding duplicate tree_node
                    full_path = prefix[:-1] + path_segment
                    full_cost = prefix_cost + segment_cost
                    # Calculate cost of truly new edges (not already in tree)
                    new_cost = sum(G[path_segment[i]][path_segment[i+1]]['cost']
                                 for i in range(len(path_segment)-1)
                                 if (path_segment[i], path_segment[i+1]) not in tree_edges)

                # Prefer paths that reuse more tree edges (lower new_cost)
                # Break ties with full_cost
                if (new_cost < best_new_cost) or (new_cost == best_new_cost and full_cost < best_cost):
                    best_cost = full_cost
                    best_new_cost = new_cost
                    best_full_path = full_path

            except (nx.NetworkXNoPath, KeyError):
                continue

        if best_full_path is None:
            # Fallback: try direct path from src
            try:
                best_full_path = nx.dijkstra_path(h, src, dst, weight="cost")
